  font-size: 7rem;
  font-weight: 800;
  letter-spacing: -0.35rem;
  line-height: 1.1;
}

p {
  font-size: 1.125rem;
  font-weight: 500;
}

section {
  position: relative;
  width: 100%;
  height: 100svh;
